mapper.select:
SELECT
FROM tb_pmb_internet_plan_list a LEFT OUTER JOIN tb_pmb_internet_mno b ON a.internet_mno_id = b.id WHERE 1=1
ORDER BY a.id DESC LIMIT #{offset}, #{recordSize}

mapper.update:
UPDATE tb_pmb_internet_plan_list 
SET		
	prod_name                 	= #{prodName}
	,internet_mno_id           	= #{internetMnoId}
	,channel_count             	= #{channelCount}
	,internet_speed            	= #{internetSpeed}
	,normal_price              	= #{normalPrice}
	,combination_price         	= #{combinationPrice}
	,normal_freeble_price      	= #{normalFreeblePrice}
	,combination_freeble_price 	= #{combinationFreeblePrice}
	,use_yn                    	= #{useYn}
	,site_sp                    	= #{siteSp}
	,manager                   	= #{modifiedId}
	,modified_date             	= Now()
	,modified_id               	= #{modifiedId}
	,stress_txt					= #{stressTxt}
WHERE id = #{id}

mapper.select:
SELECT id ,name ,mno_logo ,manager ,use_yn ,new_use_yn ,new_ui_use_yn ,alam_rcv_num FROM tb_pmb_internet_mno WHERE 1=1
AND new_ui_use_yn = 'Y'
AND new_use_yn = #{useYn}
AND id = #{mnoId}
AND use_yn = #{useYn}
AND id = #{mnoId}
order by order_no
order by id

